    ON maum.follow (followee_user_id);

-- 복합 유니크 인덱스: 중복 팔로우 방지 + 팔로우 여부 확인 최적화
ALTER TABLE maum.follow
    ADD UNIQUE INDEX uk_follow_follower_followee (follower_user_id, followee_user_id);
```

---

#### 최적화 5. Repository 최종 구성

```kotlin
// AFTER: domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepository.kt
interface FollowRepository : JpaRepository<FollowEntity, String>, FollowRepositoryCustom {

    // 단순 존재 여부 확인 (팔로우 여부 체크용, uk_follow_follower_followee 인덱스 활용)
    fun existsByFollowerUserIdAndFolloweeUserId(
        followerUserId: String,
        followeeUserId: String
    ): Boolean

    // 팔로우 수 카운트 (인덱스로 빠른 COUNT)
    fun countByFollowerUserId(followerUserId: String): Long
    fun countByFolloweeUserId(followeeUserId: String): Long
}
```

